// skillDirLabel returns a short label from a full dir path.
func skillDirLabel(dir string) string {
	// dir like /home/user/.claude/skills → "claude"
	// dir like C:\Users\user\.codex\skills → "codex"
	// walk backwards: skip last segment ("skills"), take segment before it
	clean := strings.TrimRight(strings.ReplaceAll(dir, "\\", "/"), "/")
	parts := strings.Split(clean, "/")
	for i := len(parts) - 1; i >= 0; i-- {
		seg := strings.TrimLeft(parts[i], ".")
		if seg != "" && seg != "skills" {
			return seg
		}
	}
	return dir
}

